const threshold = parseInt($env.HEALTH_AT_RISK_THRESHOLD || 50, 10);
const scored = $input.all().map(i => {
  const d = i.json;
  // Scoring components (each 0-100, weighted)
  const usage_score = Math.min(100, parseInt(d.login_days_30d||0) / 20 * 100); // target 20 days/month = 100
  const feature_score = Math.min(100, parseInt(d.features_used||0) / 5 * 100); // target 5 features = 100
  const support_score = Math.max(0, 100 - parseInt(d.support_tickets_30d||0) * 15); // each ticket -15pts
  const nps_score = d.nps_score !== '' && d.nps_score !== undefined ? (parseInt(d.nps_score||0) / 10 * 100) : 60; // default neutral
  const recency_score = Math.max(0, 100 - parseInt(d.days_since_last_login||0) * 3); // each day away -3pts
  // Weighted composite
  const health = Math.round(usage_score*0.3 + feature_score*0.2 + support_score*0.2 + nps_score*0.15 + recency_score*0.15);
  const status = health >= 80 ? 'healthy' : health >= threshold ? 'at_risk' : 'critical';
  return { ...d, health_score: Math.min(100, Math.max(0, health)), status, components: { usage: Math.round(usage_score), features: Math.round(feature_score), support: Math.round(support_score), nps: Math.round(nps_score), recency: Math.round(recency_score) } };
}).sort((a, b) => a.health_score - b.health_score);
const critical = scored.filter(s => s.status === 'critical');
const at_risk = scored.filter(s => s.status === 'at_risk');
return [{ json: { week: new Date().toISOString().slice(0,10), total: scored.length, critical_count: critical.length, at_risk_count: at_risk.length, critical, at_risk, all: scored } }];

